import logo from "./logo.svg";
import "./App.css";
import Typewriter from "typewriter-effect";

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1 className="left-header">
          <Typewriter
            options={{
              loop: true,
            }}
            onInit={(typewriter) => {
              typewriter
                .typeString(
                  `HELLO, I'M <span ClassName="highlight">BURGEON</span>, A WEB DEVELOPER 😍 `
                )
                .pauseFor(1000)
                .deleteAll()
                .typeString(
                  "I'M PASSIONATE ABOUT CREATING INTERESTING WEB PAGES 👌"
                )
                .pauseFor(1000)
                .deleteAll()
                .typeString("LET'S BUILD SOMETHING AMAZING TOGETHER 💪")
                .pauseFor(1000)
                .deleteAll()
                .start();
            }}
          />
        </h1>

        <Navbar />
      </header>
    </div>
  );
}

export default App;

const Profile = () => {
  return (
    <>
      <div>
        <img src="#" alt="burgeon" className="display-pic" />
        <h1>
          Hello <span>I'm Burgeon</span>
        </h1>
      </div>
    </>
  );
};
const Navbar = () => {};
